import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import { BASE_URL } from '../../utils/api'; 
// Предполагается, что вы используете функцию applyFilters для фильтрации
// import { applyFilters } from '../../utils/filterUtils'; 

// --- ЗАГЛУШКА ДЛЯ ФИЛЬТРАЦИИ (Вставьте свой applyFilters) ---
const applyFilters = (list, filters) => {
    // В реальном проекте здесь будет логика фильтрации и сортировки
    let filteredList = list;

    // 1. Фильтр по скидке
    if (filters.discount) {
        filteredList = filteredList.filter(item => item.discont_price !== null && item.discont_price < item.price);
    }

    // 2. Фильтр по цене
    const priceFrom = parseFloat(filters.priceFrom);
    const priceTo = parseFloat(filters.priceTo);

    if (priceFrom) {
        filteredList = filteredList.filter(item => (item.discont_price || item.price) >= priceFrom);
    }
    if (priceTo) {
        filteredList = filteredList.filter(item => (item.discont_price || item.price) <= priceTo);
    }

    // 3. Сортировка (пример)
    if (filters.sortBy === 'price_asc') {
        filteredList.sort((a, b) => (a.discont_price || a.price) - (b.discont_price || b.price));
    } else if (filters.sortBy === 'price_desc') {
        filteredList.sort((a, b) => (b.discont_price || b.price) - (a.discont_price || a.price));
    }

    return filteredList;
};
// --- КОНЕЦ ЗАГЛУШКИ ---


// --- THUNKS ---

export const fetchAllProducts = createAsyncThunk(
  'products/fetchAllProducts',
  async (_, { rejectWithValue }) => {
    try {
      const response = await fetch(`${BASE_URL}/products/all`);
      if (!response.ok) throw new Error('Failed to fetch all products.');
      return await response.json();
    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);

export const fetchDiscountedProducts = createAsyncThunk(
  'products/fetchDiscountedProducts',
  async (_, { rejectWithValue }) => {
    try {
      const response = await fetch(`${BASE_URL}/products/sale`);
      if (!response.ok) throw new Error('Failed to fetch discounted products.');
      return await response.json();
    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);

export const fetchProductsByCategory = createAsyncThunk(
  'products/fetchProductsByCategory',
  async ({ id }, { rejectWithValue }) => {
    try {
      // 🔑 API, скорее всего, вернет объект { id, title, products: [...] }
      const response = await fetch(`${BASE_URL}/categories/${id}`); 
      if (!response.ok) throw new Error('Failed to fetch products for category.');
      return await response.json();
    } catch (error) {
      return rejectWithValue(error.message);
    }
  }
);

// ... (остальные thunks)

// --- INITIAL STATE ---

const initialState = {
  list: [],
  rawList: [], // Список до применения фильтров
  selectedProduct: null,
  status: 'idle',
  detailsStatus: 'idle',
  error: null,
  filters: {
    priceFrom: '',
    priceTo: '',
    discount: false,
    sortBy: 'default',
  },
  isDiscountPage: false,
};

// --- SLICE ---
const productsSlice = createSlice({
  name: 'products',
  initialState,
  reducers: {
    setProductsFilter: (state, action) => {
      Object.assign(state.filters, action.payload);
      // Применяем фильтры сразу после их изменения к rawList
      state.list = applyFilters(state.rawList, state.filters); 
    },
    clearRawList: (state) => {
      state.rawList = [];
      state.list = [];
      state.status = 'idle';
      state.isDiscountPage = false;
    }
  },
  extraReducers: (builder) => {
    const handlePending = (state) => {
      state.status = 'loading';
      state.error = null;
    };

    const handleFulfilled = (state, rawData, isDiscount) => {
      state.status = 'succeeded';
      state.isDiscountPage = isDiscount;
      state.rawList = rawData;
      state.list = applyFilters(rawData, state.filters);
    };

    builder
      // ... (fetchAllProducts, fetchDiscountedProducts cases)

      .addCase(fetchProductsByCategory.pending, handlePending)
      .addCase(fetchProductsByCategory.fulfilled, (state, action) => {
        // 🟢 ИСПРАВЛЕНИЕ: Пытаемся получить products из объекта категории
        // Если API возвращает объект { products: [...] }
        const products = action.payload.products || []; 

        // Если API возвращает голый массив [...продукты]
        // const products = Array.isArray(action.payload) ? action.payload : [];

        handleFulfilled(state, products, false);
      })
      .addCase(fetchProductsByCategory.rejected, (state, action) => {
        state.status = 'failed';
        state.error = action.payload;
      });

      // ... (fetchProductById cases)
  },
});

export const { setProductsFilter, clearRawList } = productsSlice.actions;
export default productsSlice.reducer;
